def apply_config(client: KongAdminClient, config: Dict[str, Any]) -> None:
    for upstream in config.get("upstreams", []):
        upstream_name = upstream["name"]
        client.create_upstream(
            name=upstream_name,
            algorithm=upstream.get("algorithm", "round-robin"),
        )
        for target in upstream.get("targets", []):
            client.create_target(
                upstream_name=upstream_name,
                target=target["target"],
                weight=target.get("weight", 100),
            )

    for service in config.get("services", []):
        service_name = service["name"]
        if "url" in service:
            client.create_service(name=service_name, url=service["url"])
        else:
            client.create_service(
                name=service_name,
                protocol=service.get("protocol"),
                host=service.get("host"),
                port=service.get("port"),
                path=service.get("path"),
            )

        for route in service.get("routes", []):
            client.create_route(
                service_name=service_name,
                name=route["name"],
                paths=route.get("paths"),
                hosts=route.get("hosts"),
                methods=route.get("methods"),
                strip_path=route.get("strip_path", True),
                preserve_host=route.get("preserve_host", False),
            )

        for plugin in service.get("plugins", []):
            client.create_plugin(
                name=plugin["name"],
                service_name=service_name,
                config=plugin.get("config"),
            )

    for plugin in config.get("plugins", []):
        client.create_plugin(
            name=plugin["name"],
            config=plugin.get("config"),
        )


